var correlationId = msg.req.headers['x-correlation-id'] || require('crypto').randomUUID();
var originalPayload = msg.payload;
msg._saga = {
  correlationId: correlationId,
  rawInput: originalPayload,
  rawContentType: msg.req.headers['content-type'] || 'application/json',
  trace: [],
  orderId: null,
  transactionId: null,
  reservationId: null
};
console.log('[orchestration] Init saga | correlationId=' + correlationId);
return msg;

var ct = (msg._saga.rawContentType || '').toLowerCase();
if (ct.includes('xml') || ct.includes('text/plain')) {
  msg._inputFormat = 'xml';
} else if (msg._saga.rawInput && msg._saga.rawInput.oid) {
  msg._inputFormat = 'mobile';
} else {
  msg._inputFormat = 'web';
}
return msg;

var raw = msg.req ? msg.req.body : '';
var xmlStr = typeof raw === 'string' ? raw : JSON.stringify(raw);
function getAttr(str, tag, attr) { var re = new RegExp('<' + tag + '[^>]*\\b' + attr + '=["\']([^"\']+)["\']', 'i'); var m = str.match(re); return m ? m[1] : null; }
function getTag(str, tag) { var re = new RegExp('<' + tag + '(?:[^>]*)?>([\s\S]*?)<\/' + tag + '>', 'i'); var m = str.match(re); return m ? m[1].trim() : null; }
function getAllMatches(str, tag) { var re = new RegExp('<' + tag + '[\s\S]*?<\/' + tag + '>', 'gi'); var results = []; var m; while ((m = re.exec(str)) !== null) results.push(m[0]); return results; }
var orderId = getAttr(xmlStr, 'PurchaseOrder', 'orderId') || ('B2B-' + Date.now());
var orderDate = getAttr(xmlStr, 'PurchaseOrder', 'orderDate') || new Date().toISOString();
var buyerName = getTag(xmlStr, 'Name') || 'Unknown';
var buyerEmail = getTag(xmlStr, 'ContactEmail') || 'unknown@example.com';
var street = getTag(xmlStr, 'Street') || '';
var city = getTag(xmlStr, 'City') || '';
var postalCode = getTag(xmlStr, 'PostalCode') || '';
var country = getAttr(xmlStr, 'ShipToAddress', 'country') || 'GB';
var currency = getAttr(xmlStr, 'LineItems', 'currency') || 'GBP';
var lineItemXmls = getAllMatches(xmlStr, 'LineItem');
var items = lineItemXmls.map(function(li, i) { var sku = getAttr(li, 'LineItem', 'sku') || ('SKU-' + i); var qty = parseInt(getAttr(li, 'LineItem', 'quantity') || '1', 10); var desc = getTag(li, 'Description') || 'Item'; return { productId: sku.replace('SKU-', ''), productName: desc, quantity: qty, unitPrice: 0, currency: currency, taxRate: 0.20 }; });
msg.payload = { orderId: orderId, orderType: 'b2b', source: 'b2b', orderDate: orderDate, customer: { name: buyerName, email: buyerEmail, address: { street: street, city: city, postalCode: postalCode, country: country } }, items: items, currency: currency, status: 'new' };
return msg;

var m = msg.payload;
var addrParts = (m.addr || '').split(',').map(function(s) { return s.trim(); });
var currencyMap = { 840: 'USD', 978: 'EUR', 826: 'GBP' };
var currencyCode = currencyMap[m.cur] || 'EUR';
msg.payload = { orderId: m.oid || ('MOB-' + Date.now()), orderType: m.ot || 'express', source: 'mobile', orderDate: m.ts ? new Date(m.ts * 1000).toISOString() : new Date().toISOString(), customer: { name: m.cust_name || 'Unknown', email: m.cust_email || 'unknown@example.com', address: { street: addrParts[0] || '', city: addrParts[1] || '', postalCode: addrParts[2] || '', country: addrParts[3] || 'LV' } }, items: [{ productId: m.prod_id || 'UNKNOWN', productName: m.prod_name || 'Item', quantity: parseInt(m.qty, 10) || 1, unitPrice: 0, currency: currencyCode, taxRate: 0.21 }], currency: currencyCode, status: 'new' };
return msg;

var p = msg.payload;
if (!p.source) p.source = 'web';
if (!p.orderType) p.orderType = 'standard';
if (!p.status) p.status = 'new';
if (!p.orderDate) p.orderDate = new Date().toISOString();
if (p.items) p.items.forEach(function(item) { if (!item.taxRate) item.taxRate = 0.21; });
msg.payload = p;
return msg;

var saga = msg._saga;
msg._canonicalOrder = msg.payload;
msg.headers = { 'x-correlation-id': saga.correlationId, 'content-type': 'application/json' };
msg.url = (process.env.ORDER_URL || 'http://order-service:3001') + '/orders';
msg.method = 'POST';
msg._stepStart = Date.now();
return msg;

var saga = msg._saga;
saga.orderId = msg.payload.orderId;
console.log('[orchestration] order created | orderId=' + saga.orderId);
var items = msg._canonicalOrder && msg._canonicalOrder.items ? msg._canonicalOrder.items : [];
var total = items.reduce(function(s, i) { return s + (i.unitPrice || 0) * (i.quantity || 1); }, 0);
var currency = (msg._canonicalOrder && msg._canonicalOrder.currency) ? msg._canonicalOrder.currency : 'EUR';
msg.url = (process.env.PAYMENT_URL || 'http://payment-service:3002') + '/payment/authorize';
msg.method = 'POST';
msg.headers = { 'x-correlation-id': saga.correlationId, 'content-type': 'application/json' };
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, amount: total, currency: currency };
msg._stepStart = Date.now();
return msg;

var saga = msg._saga;
saga.transactionId = msg.payload.transactionId;
saga.trace.push({ step: 'payment', status: 'success', durationMs: Date.now() - msg._stepStart });
var items = msg._canonicalOrder && msg._canonicalOrder.items ? msg._canonicalOrder.items.map(function(i) { return { productId: i.productId, quantity: i.quantity }; }) : [];
msg.url = (process.env.INVENTORY_URL || 'http://inventory-service:3003') + '/inventory/reserve';
msg.method = 'POST';
msg.headers = { 'x-correlation-id': saga.correlationId, 'content-type': 'application/json' };
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, transactionId: saga.transactionId, items: items };
msg._stepStart = Date.now();
return msg;

var saga = msg._saga;
saga.trace.push({ step: 'payment', status: 'failed', reason: msg.payload.reason || 'Payment declined', durationMs: Date.now() - msg._stepStart });
return msg;

var saga = msg._saga;
saga.reservationId = msg.payload.reservationId;
saga.trace.push({ step: 'inventory', status: 'success', durationMs: Date.now() - msg._stepStart });
var customerEmail = (msg._canonicalOrder && msg._canonicalOrder.customer) ? msg._canonicalOrder.customer.email : 'customer@example.com';
msg.url = (process.env.NOTIFICATION_URL || 'http://notification-service:3004') + '/notification/send';
msg.method = 'POST';
msg.headers = { 'x-correlation-id': saga.correlationId, 'content-type': 'application/json' };
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, type: 'order_confirmed', recipient: customerEmail, message: 'Your order ' + saga.orderId + ' has been confirmed.' };
msg._stepStart = Date.now();
return msg;

var saga = msg._saga;
saga.trace.push({ step: 'inventory', status: 'failed', reason: msg.payload.reason || 'Insufficient stock', durationMs: Date.now() - msg._stepStart });
return msg;

var saga = msg._saga;
saga.trace.push({ step: 'notification', status: 'success', durationMs: Date.now() - msg._stepStart });
var sagaStore = global.get('sagaStore') || {};
sagaStore[saga.orderId] = { correlationId: saga.correlationId, priority: saga.priority, trace: JSON.parse(JSON.stringify(saga.trace)) };
global.set('sagaStore', sagaStore);
msg.statusCode = 200;
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, status: 'completed', trace: saga.trace };
return msg;

var saga = msg._saga;
saga.trace.push({ step: 'notification', status: 'failed', durationMs: Date.now() - msg._stepStart });
return msg;

var saga = msg._saga;
var sagaStore = global.get('sagaStore') || {};
sagaStore[saga.orderId || 'unknown'] = { correlationId: saga.correlationId, trace: JSON.parse(JSON.stringify(saga.trace)) };
global.set('sagaStore', sagaStore);
msg.statusCode = 200;
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, status: 'failed', trace: saga.trace };
return msg;

var saga = msg._saga;
console.log('[compensation] release inventory | orderId=' + saga.orderId + ' | reservationId=' + saga.reservationId);
msg.url = (process.env.INVENTORY_URL || 'http://inventory-service:3003') + '/inventory/release';
msg.method = 'POST';
msg.headers = { 'x-correlation-id': saga.correlationId, 'content-type': 'application/json' };
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, reservationId: saga.reservationId };
msg._stepStart = Date.now();
return msg;

var saga = msg._saga;
var durationMs = Date.now() - (msg._stepStart || 0);
if (msg.payload && msg.payload.status === 'released') {
  saga.trace.push({ step: 'compensation:inventory-release', status: 'success', durationMs: durationMs });
} else {
  saga.trace.push({ step: 'compensation:inventory-release', status: 'failed', durationMs: durationMs });
}
return msg;

var saga = msg._saga;
console.log('[compensation] refund payment | orderId=' + saga.orderId + ' | transactionId=' + saga.transactionId);
msg.url = (process.env.PAYMENT_URL || 'http://payment-service:3002') + '/payment/refund';
msg.method = 'POST';
msg.headers = { 'x-correlation-id': saga.correlationId, 'content-type': 'application/json' };
msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, transactionId: saga.transactionId };
msg._stepStart = Date.now();
return msg;

var saga = msg._saga;
var durationMs = Date.now() - (msg._stepStart || 0);
var refundOk = msg.payload && msg.payload.status === 'refunded';
if (refundOk) {
  saga.trace.push({ step: 'compensation:payment-refund', status: 'success', durationMs: durationMs });
  var sagaStore = global.get('sagaStore') || {};
  sagaStore[saga.orderId || 'unknown'] = { correlationId: saga.correlationId, trace: JSON.parse(JSON.stringify(saga.trace)) };
  global.set('sagaStore', sagaStore);
  msg.statusCode = 200;
  msg.payload = { orderId: saga.orderId, correlationId: saga.correlationId, status: 'compensated', trace: saga.trace };
  return [msg, null];
} else {
  saga.trace.push({ step: 'compensation:payment-refund', status: 'failed', durationMs: durationMs });
  msg._dlqReason = 'compensation-failed';
  return [null, msg];
}

var dlq = global.get('deadLetterQueue') || [];
var entry = {
  id: require('crypto').randomUUID(),
  timestamp: new Date().toISOString(),
  reason: msg._dlqReason || 'unrecoverable-error',
  correlationId: msg._saga ? msg._saga.correlationId : 'unknown',
  orderId: msg._saga ? msg._saga.orderId : 'unknown',
  trace: msg._saga ? JSON.parse(JSON.stringify(msg._saga.trace)) : [],
  payload: msg.payload
};
dlq.push(entry);
global.set('deadLetterQueue', dlq);
node.warn('[DLQ] Entry stored: correlationId=' + entry.correlationId + ' reason=' + entry.reason);
console.log('[DLQ]', JSON.stringify(entry));
msg.statusCode = 500;
msg.payload = { orderId: entry.orderId, correlationId: entry.correlationId, status: 'error', reason: 'Compensation failed — message sent to Dead Letter Channel', trace: entry.trace };
return msg;

msg.payload = { status: 'ok', service: 'node-red' };
msg.statusCode = 200;
return msg;

var orderId = msg.req.params.orderId;
var sagaStore = global.get('sagaStore') || {};
var saga = sagaStore[orderId];
if (!saga) {
  msg.statusCode = 404;
  msg.payload = { error: 'No trace found for orderId: ' + orderId };
} else {
  msg.statusCode = 200;
  msg.payload = { orderId: orderId, correlationId: saga.correlationId, priority: saga.priority, trace: saga.trace };
}
return msg;

var dlq = global.get('deadLetterQueue') || [];
msg.statusCode = 200;
msg.payload = { count: dlq.length, messages: dlq };
return msg;
